    <script>

        const loginBtn = document.getElementById("login-btn");
        const loginText = document.getElementById("login-text");
        const spinner = document.getElementById("login-spinner"); 
        const contactForm = document.getElementsByClassName("site-contact__form")[0];
        const successAlert = document.getElementsByClassName('site-contact__success')[0];

        contactForm.addEventListener('submit',() => {
                 loginBtn.disabled = true;
                 loginBtn.style.cursor = "not-allowed"
                 loginText.style.display = "none";
                 spinner.style.display = "flex"; 
        })

        setTimeout(() => {
            if(successAlert){
                successAlert.style.display = 'none';
            }
        },4000);
        
        const shouldScrollToContact = @json(session('success') || $errors->contact->any());

        if (shouldScrollToContact) {
            window.addEventListener('load', () => {
                const scrollToAbsoluteBottom = () => {
                        const pageBottom = Math.max(
                            document.body.scrollHeight,
                            document.documentElement.scrollHeight
                        );

                        window.scrollTo({
                            top: pageBottom,
                            behavior: 'smooth',
                        });
                };

                scrollToAbsoluteBottom();
                requestAnimationFrame(scrollToAbsoluteBottom);
                setTimeout(scrollToAbsoluteBottom, 150);
                setTimeout(scrollToAbsoluteBottom, 450);
            });
         }
    </script>
    
